import React, { useState } from "react";
import ReactDOM from "react-dom/client";
import { createTheme, ThemeProvider } from "@mui/material/styles";
import CssBaseline from "@mui/material/CssBaseline";
import App from "./App"; // or whatever your main component is named

function Root() {
  // 1. Create the global state for dark mode
  const [darkMode, setDarkMode] = useState(false);

  // 2. Build the Material-UI theme dynamically based on the state
  const theme = createTheme({
    palette: {
      mode: darkMode ? "dark" : "light",
      background: {
        default: darkMode ? "#121212" : "#ffffff",
        paper: darkMode ? "#1e1e1e" : "#ffffff",
      },
    },
  });

  return (
    // 3. Wrap your App with the ThemeProvider and CssBaseline
    <ThemeProvider theme={theme}>
      <CssBaseline />
      {/* 4. Pass the state and setter function down to your application */}
      <App darkMode={darkMode} setDarkMode={setDarkMode} />
    </ThemeProvider>
  );
}

const root = ReactDOM.createRoot(document.getElementById("root"));
root.render(
  <React.StrictMode>
    <Root />
  </React.StrictMode>,
);
